var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"침식체 주제에...... 통신을 방해했던 거냐?","JPN":"侵食体のくせに……通信を妨害してたのか？","ENG":"You're nothing but a dirty C.O... but you managed to jam my signals?","TWN":"區區侵蝕體……竟妨礙了通信？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네 입으로 직접 말하지 않았느냐. 이런 곳에서 구조를 바란다는 것이 얼마나 어리석은지 말이다.","JPN":"貴様は自分の口で言ったはずだ。このような場所で救助を望むのが、いかに愚かなことなのか。","ENG":"You said so yourself, have you not? You acknowledged what a foolish endeavor it is to hope for rescue from an abyss such as this.","TWN":"你剛剛不是親口說了嗎。在這種地方，期望救援是多麼愚蠢的行為。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"시련은 막바지에 이르렀다. 미물이여.","JPN":"試練は終盤を迎えた、微物よ。","ENG":"Your trial nears its end. Mortal.","TWN":"考驗已經到了最後關頭，微不足道的廢物。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"이제 얌전히 결말을 받아들여라.","JPN":"従順に結末を受け入れるのだ。","ENG":"Now acquiesce to the inevitability of its conclusion.","TWN":"現在乖乖接受你的結局吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......시련이라고?","JPN":"……試練だと？","ENG":"My trial?","TWN":"……考驗？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"침식체들이 갑자기 몰려든 것도, 전부 네 짓이었나?","JPN":"侵食体が突然押し寄せてきたのも、全部お前の仕業だったのか？","ENG":"Were you the one who drove all these C.O.s here?","TWN":"侵蝕體突然大量湧來，全都是你做的？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇다. 준비한 것에 비하면 보잘 것 없는 규모였지.","JPN":"左様。本来用意したのものに比べると取るに足らない規模ではあったが。","ENG":"Aye. It was but a paltry detachment of a much grander force I've prepared.","TWN":"是。與準備的東西相比，規模微不足道。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그로 인해 너희가 발악하는 모습은 훌륭한 구경거리였다.","JPN":"しかし貴様らがもがく姿は素晴らしい見世物だった。","ENG":"Even so, your desperate tantrum proved to be outstanding entertainment.","TWN":"但你們因此拼命掙扎的樣子真的很精彩。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서도 흡족해하실 만큼.","JPN":"王も満足されるほどに。","ENG":"Even the queen was pleased.","TWN":"王也很滿足。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"닥쳐......!","JPN":"黙れ！！","ENG":"Shut up!","TWN":"閉嘴……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"카운터 워치의 힘도 잃은 주제에 입만 살았구나.","JPN":"カウンターウォッチの力も失った分際で、まだ威勢を張れるようだな。","ENG":"Your words remain undaunted, even without the power of your Counter Watch.","TWN":"都失去了制裁者能量環的力量，還這麼嘴硬。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 분하다면 네 알량한 재주로 그 아이를 지켜 보아라.","JPN":"そんなに悔しいのであれば、その微々たる力であの娘を守ってみるがいい。","ENG":"See if your parlor tricks can save the child now.","TWN":"如果你這麼憤怒，就用用你那些微不足道的本事保護那個孩子吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네가 저 아이를 구할 수 없다는 사실은 처음부터 자명했도다.","JPN":"貴様にあの娘が救えないという事実は最初からわかりきっていたことだった。","ENG":"It was always evident that you could not save the child.","TWN":"你救不了那個孩子的事實從一開始就註定了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"결국 지금처럼 사지에 내몰리게 되리라는 것 역시.","JPN":"結局、今のように死地に追い込まれるということも。","ENG":"Just as it was clear that you would drive yourselves to the brink of destruction as you are now.","TWN":"最終還是會像現在一樣被逼入絕境。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"대체...... 우리한테 이러는 목적이 뭐냐? 저 꼬맹이를 가지고 뭘 어쩌려고?","JPN":"一体……私たちにこんなことをする目的は何だ？　あの子で何をどうするつもりだ？","ENG":"Why... Why the hell are you doing this to us? What do you plan to do with the kid?","TWN":"到底……為什麼這麼對我們？帶走那個孩子又能怎樣？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"방랑자가 앗아간 우리의 <color=#ffd34c>자매</color>를 재조립하는 데 쓰일 것이다.","JPN":"放浪者に奪われた我々の<color=#ffd34c>姉妹</color>を組み直すために使われるだろう。","ENG":"She shall be reassembled to replace our <color=#ffd34c>sister</color> whom the Wayfarer has taken from us.","TWN":"重新組裝被流浪者奪去的…我們的<color=#ffd34c>姐妹</color>。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"주인님의 뜻에 충실히 따를 자매를.","JPN":"主の意に忠実に従う姉妹を。","ENG":"The sister to faithfully obey the master's will.","TWN":"忠於主人命令的姐妹。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……は？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"위대하신 마왕, 타기리온께서는 아득한 옛날부터 염원하셨노라.","JPN":"偉大なる魔王、タギリオン様は遥か昔から念願しておられた。","ENG":"For eons, the great Demon Lord Thagirion has long desired...","TWN":"偉大的魔王，嗚咽者從遙遠的過去就開始期盼。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"흉측하게 부서져 버린 너희의 세계를 아름다운 모습으로 되돌리기를.","JPN":"醜く壊れてしまった貴様らの世界を美しい姿に戻すことを。","ENG":"to restore your wretched world to its former glory.","TWN":"要將你們那慘不忍睹的世界重新塑造成美好的模樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 뜻을 이루시기에는 왕을 도울 자매들의 수가 너무나도 부족하도다.","JPN":"しかし、その志を果たすには王の手足となる姉妹の数があまりにも足りぬ。","ENG":"But the sisters who must aid the queen's endeavor are far too few in number.","TWN":"但為了實現這個願望，幫助王的姐妹數量遠遠不夠。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그렇기에 왕의 뜻을 따를 수 있도록, 너희 미물들을 보다 높은 존재로 재조립하는 것이다.","JPN":"だからこそ、貴様ら下等な微物を、王の意思に従うことができるようにより高い存在に組み直すのである。","ENG":"Thus we shall reassemble ye mortals into exalted beings who may carry out the queen's will.","TWN":"因此，遵照王的意旨，將你們這些微不足道的廢物重新組裝成更高階的東西。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"마왕인지 뭔지는 몰라도...... 결국 너와 같은 그림자를 늘리겠다는 뜻 아닌가?","JPN":"魔王か何だか知らないが……つまりお前と同じシャドウを増やすという意味だな？","ENG":"I couldn't care less about this Demon Lord of yours... but you're basically just trying to make more Shadows like you, huh?","TWN":"我不知道什麼魔王……意思不就是最後像你一樣的暗影會增加嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그렇다면 꼬맹이가 아니더라도 상관없잖아!","JPN":"ならガキじゃなくてもいいだろ！","ENG":"Then can't you just take anyone else? Anyone else but the kid!","TWN":"如果是那樣，是不是這個小鬼又有什麼關係！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"쿨럭......! 빌어먹을......!","JPN":"ガハッ……！　くそっ……！","ENG":"*Cough!* Darn it!","TWN":"咳咳……！可惡……！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_BIG"},{"id":"L47_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐야......? 아무것도 없는데, 방금 뭘 맞은 거지......?","JPN":"なんだ……？　何もないのに、今何に攻撃されたんだ？","ENG":"What? There's nothing here... What just hit me?","TWN":"怎麼會這樣……？明明什麼都沒有，我剛剛是被什麼打到……？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"건방진 것. 왕께서 내린 결정에 감히 토를 다느냐.","JPN":"生意気な微物め。王が下した決断に身の程知らずが文句をつけるのか。","ENG":"Insolent fool. You dare question the queen's decision?","TWN":"傲慢的傢伙，竟敢質疑王的決定。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"명운이 바닥난 너를 고통 속에서 몸부림치게 만드는 것은 내게 쉬운 일이로다.","JPN":"命運が底をついた貴様を苦痛の中で苦しませるのは余にとって容易なこと。","ENG":"It is far too easy for me to make you writhe in agony as you expire.","TWN":"讓你在痛苦中掙扎，對我來說可是件容易的事情。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"이 소리는...... 설마, 꼬맹이가......","JPN":"この声は……まさか、ガキが……","ENG":"That sound... Is the kid...","TWN":"這個聲音……難道，小鬼……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"아아, 들리는구나. 손에 잡힐 듯 감미로운 절규가.","JPN":"ああ、聞こえるのか。手でも掴めそうな甘美な絶叫が。","ENG":"Ah, I can hear it. A scream so succulent that I can almost touch it.","TWN":"啊啊，聽到了。這動聽的慘叫聲。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그곳에서 무력하게 지켜보아라.","JPN":"そこで無力のまま見守るがよい。","ENG":"I shall grant you the honor of watching helplessly...","TWN":"就在那裡好好看著吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"저 아이가 스스로 목숨을 구걸하며 무너지는 모습을.","JPN":"あの娘が自ら命乞いして崩れてゆく様を。","ENG":"As the child begs for her life and falters.","TWN":"看那孩子倒地乞求的樣子。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이가...... 아니라......","JPN":"ガキじゃ……なくて……","ENG":"Does it... have to be the kid?","TWN":"不行……小鬼……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나로는...... 안 되는 건가?","JPN":"私じゃ……ダメなのか？","ENG":"Could you... take me instead?","TWN":"難道我……就不行嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"호오......","JPN":"ほう……","ENG":"Oh?","TWN":"謔笑……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"스스로 축복을 구걸하는 것인가. 어리석은 자여.","JPN":"自ら祝福を物乞いするのか。愚者よ。","ENG":"Are you pleading for the blessing of your own accord? How foolish.","TWN":"難道是在乞求自己也能獲得祝福嗎，愚蠢的人類。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"어리석든 말든...... 상관없어......","JPN":"愚かであろうがなかろうが……関係ない……","ENG":"I don't care... if it's foolish or not...","TWN":"愚不愚蠢……都不要緊……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"꼬맹이만...... 지킬 수 있다면.","JPN":"あの子さえ……守られるなら……","ENG":"As long as... the kid is safe...","TWN":"如果……能守護她。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"황송하게 여기거라, 미물아.","JPN":"恐縮に思え、下等な微物よ。","ENG":"Be grateful, ye petty mortal.","TWN":"惶恐吧，微不足道的廢物。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서 스스로 굴종하는 자의 뜻을 갸륵하게 여기시는도다.","JPN":"王は自ら屈従する者の意思を殊勝に思われるお方である。","ENG":"The queen is pleased by your submission.","TWN":"王會認為主動屈從者的勇氣可嘉。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네가 바라는 바를 이룰 수 있을지...... 그분께서 무척 흥미로워하시겠구나.","JPN":"貴様が望むことを叶えられるか……あの方なら興味深く見守ってくださるはず。","ENG":"The king will be eager to see... if you shall indeed achieve what you desire.","TWN":"你期待的能否實現呢……王應該非常感興趣吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"고개를 들어 보아라. 이것은 너로부터 말미암아 완성될 자매일지니.","JPN":"頭を上げたまえ。これは貴様によって完成される姉妹である。","ENG":"Raise your head and behold. This is the sister that shall become complete through you.","TWN":"抬起頭來看看吧，因為這是從你開始完成的姐妹。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_WIND"},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그 수정은...... 내가, 깨뜨렸던......","JPN":"その水晶は……私が壊した……","ENG":"That crystal... I thought I broke it...","TWN":"那個水晶……我，打碎的那個……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕의 뜻이 담긴 물건이 그리 쉽게 망가질 줄 알았느냐.","JPN":"王の意思が込められたものが、そんなに簡単に壊れると思ったのか。","ENG":"Did you truly think an object blessed with the queen's will would break so easily?","TWN":"包含著王意志的東西怎麼可能那麼容易被毀掉。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"자아, 아주 고통스럽겠지만......","JPN":"さあ、さぞかし苦しいだろうが……","ENG":"Now, this will be extremely painful...","TWN":"來，雖然會非常痛苦……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"끔찍하리만치 황홀하리로다.","JPN":"ぞっとするほど、うっとりするのであろう。","ENG":"But it shall also bring you terrifying ecstasy...","TWN":"卻也耀眼到讓你恐懼。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};